import React from "react";

const BarraHorizontal = ({
  texto,
  height = "clamp(0.5vh, 1.36vh, 1.5vh)", // Extremadamente delgada usando proporción áurea mínima
  margenHorizontal = "clamp(5vw, 10vw, 15vw)",
  imagen,
}) => {
  const containerStyle = { height };

  const imageStyle = {
    backgroundImage: `url(${imagen})`,
    width: margenHorizontal,
  };

  return (
    <div 
      style={{
        ...containerStyle,
        borderTopWidth: '0.5px',
        borderBottomWidth: '0.5px'
      }}
      className="w-full flex items-center overflow-hidden bg-surface border-stroke shadow-sm"
    >
      <div
        style={imageStyle}
        className="bg-repeat-x bg-center h-[90%] flex-shrink-0 bg-[length:auto_100%] opacity-70"
      />
      <div
        className="flex-grow h-full flex items-center justify-center font-bodoni text-black text-[6px] md:text-[7px] lg:text-[8px] xl:text-[9px] tracking-wider transform -translate-y-[1%] font-bold uppercase px-0.5 md:px-1"
      >
        {texto}
      </div>
      <div
        style={imageStyle}
        className="bg-repeat-x bg-center h-[90%] flex-shrink-0 bg-[length:auto_100%] opacity-70"
      />
    </div>
  );
};

export default BarraHorizontal;
